 1	/**
 2	 * Displays a "404 Page Not Found" message with an option to navigate back to the homepage.
 3	 * Utilizes PatternFly components for a consistent and accessible UI,
 4	 * providing a clear indication that the requested page could not be found.
 5	 *
 6	 * @module notFound
 7	 */
 8	import React from 'react';
 9	import { useTranslation } from 'react-i18next';
10	import { useNavigate } from 'react-router-dom';
11	import {
12	  Button,
13	  EmptyState,
14	  EmptyStateBody,
15	  EmptyStateFooter,
16	  EmptyStateHeader,
17	  EmptyStateIcon,
18	  PageSection
19	} from '@patternfly/react-core';
20	import { ExclamationTriangleIcon } from '@patternfly/react-icons';
21	
22	const NotFound: React.FC = () => {
23	  const { t } = useTranslation();
24	  const navigate = useNavigate();
25	
26	  return (
27	    <PageSection>
28	      <EmptyState variant="full">
29	        <EmptyStateHeader
30	          titleText={t('view.empty-state_title_not-found')}
31	          icon={<EmptyStateIcon icon={ExclamationTriangleIcon} />}
32	          headingLevel="h1"
33	        />
34	        <EmptyStateBody>{t('view.empty-state_description_not-found')}</EmptyStateBody>
35	        <EmptyStateFooter>
36	          <Button onClick={() => navigate('/')}>{t('view.label_not-found_home')}</Button>
37	        </EmptyStateFooter>
38	      </EmptyState>
39	    </PageSection>
40	  );
41	};
42	
43	export { NotFound as default, NotFound };

